package com.google.devtools.build.lib.packages;

import static com.google.common.truth.Truth.assertThat;

import com.google.devtools.build.lib.packages.util.PackageLoadingTestCase;
import net.starlark.java.eval.StarlarkInt;
import org.junit.Before;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.junit.runners.JUnit4;

/**
 * Unit tests for Starlark rule evaluation in BUILD files, covering rule instantiation, attribute
 * validation, and error handling.
 */
@RunWith(JUnit4.class)
public final class StarlarkRuleEvalTest extends PackageLoadingTestCase {

  @Before
  public void setUpCustomRule() throws Exception {
    scratch.file("rules/BUILD");
    scratch.file(
        "rules/my_rule.bzl",
        """
        def _impl(ctx):
            pass

        my_rule = rule(
            implementation = _impl,
            attrs = {
                "srcs": attr.label_list(allow_files = True),
                "out": attr.string(mandatory = True),
                "deps": attr.label_list(),
                "num": attr.int(default = 42),
            },
        )
        """);
  }

  private Package loadPackage(String pkgid) throws Exception {
    return getTarget("//" + pkgid + ":BUILD").getPackage();
  }

  /** Test 1: Basic rule instantiation with required attributes. */
  @Test
  public void testBasicRuleInstantiation() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(
            name = "my_target",
            out = "output.txt",
        )
        """);

    Rule rule = (Rule) getTarget("//pkg:my_target");
    assertThat(rule).isNotNull();
    assertThat(rule.getName()).isEqualTo("my_target");
    assertThat(rule.getRuleClass()).isEqualTo("my_rule");
    assertThat(rule.containsErrors()).isFalse();
  }

  /** Test 2: Missing required attribute produces an error. */
  @Test
  public void testMissingRequiredAttributeProducesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(name = "my_target")
        """);

    Package pkg = loadPackage("pkg");
    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("missing value for mandatory attribute 'out' in 'my_rule' rule");
  }

  /** Test 3: Attribute type validation — passing a list where a string is expected. */
  @Test
  public void testAttributeTypeValidation() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(
            name = "my_target",
            out = ["not_a_string"],
        )
        """);

    Package pkg = loadPackage("pkg");
    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("expected value of type 'string'");
  }

  /** Test 4: Default attribute values are applied when not specified. */
  @Test
  public void testDefaultAttributeValuesApplied() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(
            name = "my_target",
            out = "output.txt",
        )
        """);

    Rule rule = (Rule) getTarget("//pkg:my_target");
    assertThat(rule.containsErrors()).isFalse();

    AttributeMap attrs = RawAttributeMapper.of(rule);
    assertThat(attrs.get("num", Type.INTEGER)).isEqualTo(StarlarkInt.of(42));
    assertThat(attrs.get("srcs", BuildType.LABEL_LIST)).isEmpty();
  }

  /** Test 5: Visibility attribute can be set and is reflected in the rule. */
  @Test
  public void testVisibilityAttributeHandling() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(
            name = "my_public_target",
            out = "output.txt",
            visibility = ["//visibility:public"],
        )
        """);

    Rule rule = (Rule) getTarget("//pkg:my_public_target");
    assertThat(rule).isNotNull();
    assertThat(rule.containsErrors()).isFalse();
    assertThat(rule.getVisibility().getDeclaredLabels())
        .containsExactly(RuleVisibility.PUBLIC_LABEL);
  }

  /** Test 6: A valid rule name is accepted without errors. */
  @Test
  public void testValidRuleName() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(
            name = "valid_rule_name",
            out = "output.txt",
        )
        """);

    Rule rule = (Rule) getTarget("//pkg:valid_rule_name");
    assertThat(rule).isNotNull();
    assertThat(rule.getName()).isEqualTo("valid_rule_name");
    assertThat(rule.containsErrors()).isFalse();
  }

  /** Test 7: An invalid rule name (containing ':') produces an error. */
  @Test
  public void testInvalidRuleName() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")

        my_rule(name = "invalid:name", out = "output.txt")
        """);

    Package pkg = loadPackage("pkg");
    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("target names may not contain ':'");
  }
}

