330:   /**
331:    * A Utility method that generates build file rules for tests.
332:    *
333:    * @param rule the name of the rule class.
334:    * @param name the name of the rule instance.
335:    * @param body an array of strings containing the contents of the rule.
336:    * @return a string containing the build file rule.
337:    */
338:   protected static String genRule(String rule, String name, String... body) {
339:     StringBuilder buf = new StringBuilder();
340:     buf.append(rule);
341:     buf.append("(name='");
342:     buf.append(name);
343:     buf.append("',\n");
344:     for (String line : body) {
345:       buf.append(line);
346:     }
347:     buf.append(")\n");
348:     return buf.toString();
349:   }
