351:   /**
352:    * A utility function which generates the "deps" clause for a build file rule from a list of
353:    * targets.
354:    *
355:    * @param depTargets the list of targets.
356:    * @return a string containing the deps clause
357:    */
358:   protected static String deps(String... depTargets) {
359:     StringBuilder buf = new StringBuilder();
360:     buf.append("    deps=[");
361:     String sep = "'";
362:     for (String dep : depTargets) {
363:       buf.append(sep);
364:       buf.append(dep);
365:       buf.append("'");
366:       sep = ", '";
367:     }
368:     buf.append("]");
369:     return buf.toString();
370:   }
